const FAVICON_BASE64 =
  "";

const faviconBytes = Uint8Array.from(atob(FAVICON_BASE64), (char) => char.charCodeAt(0));

export function GET() {
  return new Response(faviconBytes, {
    headers: {
      "Content-Type": "image/x-icon",
      "Cache-Control": "public, max-age=31536000, immutable",
    },
  });
}
